sim_expected<PlsimMarginal>
fit_plsim_marginal(double skewness,
                   double excess_kurtosis,
                   const PlsimOptions& options) {
  if (auto ok = validate_options(options); !ok.has_value()) {
    return std::unexpected(ok.error());
  }
  if (!std::isfinite(skewness) || !std::isfinite(excess_kurtosis)) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "fit_plsim_marginal: target moments must be finite"));
  }
  if (excess_kurtosis < skewness * skewness - 2.0) {
    return std::unexpected(make_err(
        SimError::Kind::CalibrationFailed,
        "fit_plsim_marginal: requested moments are infeasible"));
  }

  const Eigen::VectorXd gamma = regular_gamma(options.num_segments);
  SimError last_error{SimError::Kind::CalibrationFailed,
                      "fit_plsim_marginal: piecewise-linear moment solve did not converge"};
  for (const auto& start : plsim_starts(options.num_segments, options.monotone)) {
    auto slopes_or = solve_slopes_from_start(
        start, gamma, skewness, excess_kurtosis, options);
    if (!slopes_or.has_value()) {
      last_error = slopes_or.error();
      continue;
    }

    Eigen::VectorXd a = *slopes_or;
    Eigen::VectorXd b = continuity_intercepts(a, gamma);
    Eigen::Vector4d m = raw_moments(a, b, gamma);
    const double var = m(1) - m(0) * m(0);
    if (!(var > 0.0) || !std::isfinite(var)) continue;
    a.array() /= std::sqrt(var);
    b = continuity_intercepts(a, gamma);
    m = raw_moments(a, b, gamma);

    PlsimMarginal out;
    out.gamma = gamma;
    out.a = a;
    out.b = b;
    out.mean = m(0);
    out.variance = m(1) - m(0) * m(0);
    const double mu3 = m(2) - 3.0 * m(0) * m(1) + 2.0 * m(0) * m(0) * m(0);
    const double mu4 = m(3) - 4.0 * m(0) * m(2) +
                       6.0 * m(0) * m(0) * m(1) -
                       3.0 * m(0) * m(0) * m(0) * m(0);
    out.skewness = mu3 / std::pow(out.variance, 1.5);
    out.excess_kurtosis = mu4 / (out.variance * out.variance) - 3.0;
    auto h_or = plsim_hermite_coefficients(out, options.hermite_order);
    if (!h_or.has_value()) return std::unexpected(h_or.error());
    out.hermite_coefficients = *h_or;
    return out;
  }
  return std::unexpected(last_error);
}

sim_expected<Eigen::VectorXd>
plsim_hermite_coefficients(const PlsimMarginal& marginal, int order) {
  if (order < 0 || marginal.a.size() == 0 ||
      marginal.b.size() != marginal.a.size() ||
      marginal.gamma.size() + 1 != marginal.a.size() ||
      !marginal.a.allFinite() || !marginal.b.allFinite() ||
      !marginal.gamma.allFinite()) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "plsim_hermite_coefficients: invalid marginal or order"));
  }

  Eigen::VectorXd c(order + 1);
  for (int n = 0; n <= order; ++n) {
    double numerator = 0.0;
    for (Eigen::Index i = 0; i < marginal.a.size(); ++i) {
      const double lo = (i == 0) ? -std::numeric_limits<double>::infinity()
                                : marginal.gamma(i - 1);
      const double hi = (i + 1 == marginal.a.size())
                            ? std::numeric_limits<double>::infinity()
                            : marginal.gamma(i);
      const double iz = hermite_interval_integral(n + 1, lo, hi) +
                        static_cast<double>(n) *
                            (n == 0 ? 0.0 : hermite_interval_integral(n - 1, lo, hi));
      numerator += marginal.a(i) * iz +
                   marginal.b(i) * hermite_interval_integral(n, lo, hi);
    }
    c(n) = numerator / factorial(n);
  }
  return c;
}

double plsim_apply(const PlsimMarginal& marginal, double z) noexcept {
  Eigen::Index k = 0;
  while (k < marginal.gamma.size() && z > marginal.gamma(k)) ++k;
  return marginal.a(k) * z + marginal.b(k);
}

sim_expected<double>
plsim_covariance_hermite(const PlsimMarginal& left,
                         const PlsimMarginal& right,
                         double rho,
                         int order) {
  if (!std::isfinite(rho) || std::abs(rho) >= 1.0 || order < 1) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "plsim_covariance_hermite: invalid rho or order"));
  }
  Eigen::VectorXd lc = left.hermite_coefficients;
  Eigen::VectorXd rc = right.hermite_coefficients;
  if (lc.size() <= order) {
    auto lc_or = plsim_hermite_coefficients(left, order);
    if (!lc_or.has_value()) return std::unexpected(lc_or.error());
    lc = *lc_or;
  }
  if (rc.size() <= order) {
    auto rc_or = plsim_hermite_coefficients(right, order);
    if (!rc_or.has_value()) return std::unexpected(rc_or.error());
    rc = *rc_or;
  }
  double out = 0.0;
  double rho_power = 1.0;
  for (int n = 1; n <= order; ++n) {
    rho_power *= rho;
    out += factorial(n) * lc(n) * rc(n) * rho_power;
  }
  return out;
}

sim_expected<double>
plsim_covariance_quadrature(const PlsimMarginal& left,
                            const PlsimMarginal& right,
                            double rho,
                            int quadrature_points) {
  if (!std::isfinite(rho) || std::abs(rho) >= 1.0) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "plsim_covariance_quadrature: rho must be finite with |rho| < 1"));
  }
  auto gh_or = gauss_hermite(quadrature_points);
  if (!gh_or.has_value()) return std::unexpected(gh_or.error());
  const auto& gh = *gh_or;

  const double scale = std::sqrt(std::max(0.0, 1.0 - rho * rho));
  double exy = 0.0;
  double ex = 0.0;
  double ey = 0.0;
  for (Eigen::Index i = 0; i < gh.nodes.size(); ++i) {
    const double x = std::sqrt(2.0) * gh.nodes(i);
    const double wx = gh.weights(i) / std::sqrt(std::numbers::pi);
    const double hx = plsim_apply(left, x);
    ex += wx * hx;
    for (Eigen::Index j = 0; j < gh.nodes.size(); ++j) {
      const double e = std::sqrt(2.0) * gh.nodes(j);
      const double y = rho * x + scale * e;
      const double w = wx * gh.weights(j) / std::sqrt(std::numbers::pi);
      const double hy = plsim_apply(right, y);
      exy += w * hx * hy;
    }
  }
  for (Eigen::Index j = 0; j < gh.nodes.size(); ++j) {
    const double y = std::sqrt(2.0) * gh.nodes(j);
    const double wy = gh.weights(j) / std::sqrt(std::numbers::pi);
    ey += wy * plsim_apply(right, y);
  }
  return exy - ex * ey;
}

namespace {

template <class Fn>
double simpson(const Fn& f, double a, double b) {
  const double c = 0.5 * (a + b);
  return (b - a) * (f(a) + 4.0 * f(c) + f(b)) / 6.0;
}

template <class Fn>
double adaptive_simpson(const Fn& f,
                        double a,
                        double b,
                        double eps,
                        double whole,
                        int depth) {
  const double c = 0.5 * (a + b);
  const double left = simpson(f, a, c);
  const double right = simpson(f, c, b);
  const double delta = left + right - whole;
  if (depth <= 0 || std::abs(delta) <= 15.0 * eps) {
    return left + right + delta / 15.0;
  }
  return adaptive_simpson(f, a, c, 0.5 * eps, left, depth - 1) +
         adaptive_simpson(f, c, b, 0.5 * eps, right, depth - 1);
}

template <class Fn>
double integrate_finite(const Fn& f, double lo, double hi, double eps) {
  if (!(hi > lo)) return 0.0;
  const double whole = simpson(f, lo, hi);
  return adaptive_simpson(f, lo, hi, eps, whole, 18);
}

struct RectMoments {
  double p = 0.0;
  double mx = 0.0;
  double my = 0.0;
  double mxy = 0.0;
};

RectMoments bvn_rectangle_moments(double xlo,
                                  double xhi,
                                  double ylo,
                                  double yhi,
                                  double rho,
                                  double eps) {
  const double lo = finite_bound(xlo);
  const double hi = finite_bound(xhi);
  if (!(hi > lo)) return {};

  const double s = std::sqrt(std::max(0.0, 1.0 - rho * rho));
  auto parts = [&](double x) {
    const double ax = std::isinf(ylo) && ylo < 0.0
                          ? -std::numeric_limits<double>::infinity()
                          : (ylo - rho * x) / s;
    const double bx = std::isinf(yhi) && yhi > 0.0
                          ? std::numeric_limits<double>::infinity()
                          : (yhi - rho * x) / s;
    const double q = normal_cdf(bx) - normal_cdf(ax);
    const double tail = normal_pdf(ax) - normal_pdf(bx);
    const double phi_x = normal_pdf(x);
    const double y_cond = rho * x * q + s * tail;
    Eigen::Vector4d out;
    out << phi_x * q,
           x * phi_x * q,
           phi_x * y_cond,
           x * phi_x * y_cond;
    return out;
  };

  RectMoments out;
  auto fp = [&](double x) { return parts(x)(0); };
  auto fmx = [&](double x) { return parts(x)(1); };
  auto fmy = [&](double x) { return parts(x)(2); };
  auto fmxy = [&](double x) { return parts(x)(3); };
  out.p = integrate_finite(fp, lo, hi, eps);
  out.mx = integrate_finite(fmx, lo, hi, eps);
  out.my = integrate_finite(fmy, lo, hi, eps);
  out.mxy = integrate_finite(fmxy, lo, hi, eps);
  return out;
}

}  // namespace

sim_expected<double>
plsim_covariance_rectangle(const PlsimMarginal& left,
                           const PlsimMarginal& right,
                           double rho,
                           const PlsimOptions& options) {
  if (auto ok = validate_options(options); !ok.has_value()) {
    return std::unexpected(ok.error());
  }
  if (!std::isfinite(rho) || std::abs(rho) >= 1.0) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "plsim_covariance_rectangle: rho must be finite with |rho| < 1"));
  }
  if (left.a.size() == 0 || right.a.size() == 0 ||
      left.b.size() != left.a.size() || right.b.size() != right.a.size() ||
      left.gamma.size() + 1 != left.a.size() ||
      right.gamma.size() + 1 != right.a.size()) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "plsim_covariance_rectangle: invalid marginal"));
  }

  const double eps = std::min(1e-9, options.correlation_tol * 0.1);
  double cov = 0.0;
  for (Eigen::Index i = 0; i < left.a.size(); ++i) {
    const double xlo = (i == 0) ? -std::numeric_limits<double>::infinity()
                                : left.gamma(i - 1);
    const double xhi = (i + 1 == left.a.size())
                           ? std::numeric_limits<double>::infinity()
                           : left.gamma(i);
    for (Eigen::Index j = 0; j < right.a.size(); ++j) {
      const double ylo = (j == 0) ? -std::numeric_limits<double>::infinity()
                                  : right.gamma(j - 1);
      const double yhi = (j + 1 == right.a.size())
                             ? std::numeric_limits<double>::infinity()
                             : right.gamma(j);
      const RectMoments m =
          bvn_rectangle_moments(xlo, xhi, ylo, yhi, rho, eps);
      cov += left.a(i) * right.a(j) * m.mxy +
             left.a(i) * right.b(j) * m.mx +
             left.b(i) * right.a(j) * m.my +
             left.b(i) * right.b(j) * m.p;
    }
  }
  if (!std::isfinite(cov)) {
    return std::unexpected(make_err(
        SimError::Kind::NumericIssue,
        "plsim_covariance_rectangle: covariance became non-finite"));
  }
  return cov;
}

sim_expected<PlsimCalibration>
calibrate_plsim(
    const Eigen::Ref<const Eigen::MatrixXd>& target_corr,
    const Eigen::Ref<const Eigen::VectorXd>& target_skewness,
    const Eigen::Ref<const Eigen::VectorXd>& target_excess_kurtosis,
    PlsimCovarianceMethod method,
    const PlsimOptions& options) {
  auto diag_or = diagnose_plsim(
      target_corr, target_skewness, target_excess_kurtosis, method, options);
  if (!diag_or.has_value()) return std::unexpected(diag_or.error());
  if (!diag_or->pairwise_complete) {
    return std::unexpected(make_err(
        SimError::Kind::CalibrationFailed,
        diag_or->failure_detail.empty()
            ? "calibrate_plsim: pairwise calibration failed"
            : diag_or->failure_detail));
  }
  if (!diag_or->intermediate_positive_definite) {
    return std::unexpected(make_err(
        SimError::Kind::NonPositiveDefinite,
        diag_or->failure_detail.empty()
            ? "calibrate_plsim: intermediate correlation is not positive definite"
            : diag_or->failure_detail));
  }
  return std::move(diag_or->calibration);
}

sim_expected<PlsimDiagnostics>
diagnose_plsim(
    const Eigen::Ref<const Eigen::MatrixXd>& target_corr,
    const Eigen::Ref<const Eigen::VectorXd>& target_skewness,
    const Eigen::Ref<const Eigen::VectorXd>& target_excess_kurtosis,
    PlsimCovarianceMethod method,
    const PlsimOptions& options) {
  if (auto ok = validate_plsim_inputs(
          target_corr, target_skewness, target_excess_kurtosis, options);
      !ok.has_value()) {
    return std::unexpected(ok.error());
  }

  const Eigen::Index p = target_corr.rows();
  PlsimDiagnostics out;
  out.calibration.marginals.reserve(static_cast<std::size_t>(p));
  for (Eigen::Index j = 0; j < p; ++j) {
    auto marginal_or = fit_plsim_marginal(
        target_skewness(j), target_excess_kurtosis(j), options);
    if (!marginal_or.has_value()) return std::unexpected(marginal_or.error());
    out.calibration.marginals.push_back(std::move(*marginal_or));
  }

  out.calibration.intermediate_corr = Eigen::MatrixXd::Identity(p, p);
  out.calibration.achieved_corr = Eigen::MatrixXd::Identity(p, p);
  out.calibration.iterations = Eigen::MatrixXi::Zero(p, p);
  out.lower_bound_corr = Eigen::MatrixXd::Identity(p, p);
  out.upper_bound_corr = Eigen::MatrixXd::Identity(p, p);
  out.pair_ok = Eigen::MatrixXi::Zero(p, p);
  out.pair_ok.diagonal().array() = 1;
  out.pair_error.assign(static_cast<std::size_t>(p * p), {});
  out.pairwise_complete = true;

  const PlsimCovarianceMethod bound_method = terminal_covariance_method(method);
  for (Eigen::Index i = 0; i < p; ++i) {
    for (Eigen::Index j = i + 1; j < p; ++j) {
      auto lo_or = plsim_covariance_by_method(
          out.calibration.marginals[static_cast<std::size_t>(i)],
          out.calibration.marginals[static_cast<std::size_t>(j)],
          -options.rho_bound, bound_method, options);
      auto hi_or = plsim_covariance_by_method(
          out.calibration.marginals[static_cast<std::size_t>(i)],
          out.calibration.marginals[static_cast<std::size_t>(j)],
          options.rho_bound, bound_method, options);
      if (lo_or.has_value() && hi_or.has_value()) {
        out.lower_bound_corr(i, j) = out.lower_bound_corr(j, i) =
            std::min(*lo_or, *hi_or);
        out.upper_bound_corr(i, j) = out.upper_bound_corr(j, i) =
            std::max(*lo_or, *hi_or);
      }

      auto rho_or = solve_intermediate_corr(
          out.calibration.marginals[static_cast<std::size_t>(i)],
          out.calibration.marginals[static_cast<std::size_t>(j)],
          target_corr(i, j), method, options);
      if (!rho_or.has_value()) {
        out.pairwise_complete = false;
        out.pair_ok(i, j) = out.pair_ok(j, i) = 0;
        const std::string detail = rho_or.error().detail;
        out.pair_error[pair_error_index(p, i, j)] = detail;
        out.pair_error[pair_error_index(p, j, i)] = detail;
        if (out.failure_detail.empty()) out.failure_detail = detail;
        continue;
      }
      const double rho = rho_or->first;
      out.calibration.intermediate_corr(i, j) = rho;
      out.calibration.intermediate_corr(j, i) = rho;
      out.calibration.iterations(i, j) = rho_or->second;
      out.calibration.iterations(j, i) = rho_or->second;
      auto achieved_or = plsim_covariance_by_method(
          out.calibration.marginals[static_cast<std::size_t>(i)],
          out.calibration.marginals[static_cast<std::size_t>(j)], rho, method,
          options);
      if (!achieved_or.has_value()) {
        out.pairwise_complete = false;
        const std::string detail = achieved_or.error().detail;
        out.pair_error[pair_error_index(p, i, j)] = detail;
        out.pair_error[pair_error_index(p, j, i)] = detail;
        if (out.failure_detail.empty()) out.failure_detail = detail;
        continue;
      }
      out.pair_ok(i, j) = out.pair_ok(j, i) = 1;
      out.calibration.achieved_corr(i, j) = *achieved_or;
      out.calibration.achieved_corr(j, i) = *achieved_or;
    }
  }

  out.min_intermediate_eigenvalue =
      min_eigenvalue_symmetric(out.calibration.intermediate_corr);
  auto root_or = cholesky_factor_with_jitter(
      out.calibration.intermediate_corr, options.cholesky_jitter);
  out.intermediate_positive_definite = out.pairwise_complete && root_or.has_value();
  if (!out.intermediate_positive_definite && out.failure_detail.empty()) {
    out.failure_detail = root_or.error().detail;
  }
  return out;
}

sim_expected<Eigen::MatrixXd>
simulate_plsim_matrix(Eigen::Index n,
                      const PlsimCalibration& calibration,
                      std::mt19937_64& rng,
                      const PlsimOptions& options) {
  if (auto ok = validate_options(options); !ok.has_value()) {
    return std::unexpected(ok.error());
  }
  if (n <= 0) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "simulate_plsim_matrix: n must be positive"));
  }
  const Eigen::Index p = static_cast<Eigen::Index>(calibration.marginals.size());
  if (p == 0 || calibration.intermediate_corr.rows() != p ||
      calibration.intermediate_corr.cols() != p ||
      !calibration.intermediate_corr.allFinite()) {
    return std::unexpected(make_err(
        SimError::Kind::InvalidInput,
        "simulate_plsim_matrix: invalid calibration"));
  }
  auto root_or = cholesky_factor_with_jitter(
      calibration.intermediate_corr, options.cholesky_jitter);
  if (!root_or.has_value()) return std::unexpected(root_or.error());
  const Eigen::MatrixXd& root = *root_or;

  std::normal_distribution<double> normal(0.0, 1.0);
  Eigen::MatrixXd Z(n, p);
  for (Eigen::Index i = 0; i < n; ++i) {
    for (Eigen::Index j = 0; j < p; ++j) Z(i, j) = normal(rng);
  }
  Z = Z * root.transpose();

  Eigen::MatrixXd X(n, p);
  for (Eigen::Index i = 0; i < n; ++i) {
    for (Eigen::Index j = 0; j < p; ++j) {
      X(i, j) = plsim_apply(
          calibration.marginals[static_cast<std::size_t>(j)], Z(i, j));
    }
  }
  return X;
}

sim_expected<Eigen::MatrixXd>
simulate_plsim_matrix(
    Eigen::Index n,
    const Eigen::Ref<const Eigen::MatrixXd>& target_corr,
    const Eigen::Ref<const Eigen::VectorXd>& target_skewness,
    const Eigen::Ref<const Eigen::VectorXd>& target_excess_kurtosis,
    std::mt19937_64& rng,
    PlsimCovarianceMethod method,
    const PlsimOptions& options) {
  auto cal_or = calibrate_plsim(
      target_corr, target_skewness, target_excess_kurtosis, method, options);
  if (!cal_or.has_value()) return std::unexpected(cal_or.error());
  return simulate_plsim_matrix(n, *cal_or, rng, options);
}

sim_expected<data::RawData>
simulate_plsim_raw(
    Eigen::Index n,
    const Eigen::Ref<const Eigen::MatrixXd>& target_corr,
    const Eigen::Ref<const Eigen::VectorXd>& target_skewness,
    const Eigen::Ref<const Eigen::VectorXd>& target_excess_kurtosis,
    std::mt19937_64& rng,
    PlsimCovarianceMethod method,
    const PlsimOptions& options) {
  auto X_or = simulate_plsim_matrix(
      n, target_corr, target_skewness, target_excess_kurtosis, rng, method, options);
  if (!X_or.has_value()) return std::unexpected(X_or.error());
  data::RawData raw;
  raw.X.push_back(std::move(*X_or));
  return raw;
}

